"""The Strategy seam: how an amount becomes per-participant shares (in cents)."""
from __future__ import annotations

from abc import ABC, abstractmethod

from models import SplitType, InvalidExpenseError


class SplitStrategy(ABC):
    # ── WHY THIS CLASS ────────────────────────────────────────────────────────
    # The one thing that varies between split types is share computation. Make it
    # an interface so the manager never branches on type and new types just plug in.
    # 🎙️ "Each split type is its own calculator behind this one method."
    @abstractmethod
    def compute(self, amount_cents: int, participants: list[str],
                exact_cents: list[int] | None = None) -> list[int]:
        ...


class EqualSplitStrategy(SplitStrategy):
    def compute(self, amount_cents, participants, exact_cents=None):
        n = len(participants)
        if n == 0:
            raise InvalidExpenseError("need at least one participant")
        base = amount_cents // n
        rem = amount_cents % n
        # WHY: hand the leftover cents to the FIRST `rem` participants.
        #      100.00 / 3 -> 3334, 3333, 3333  == 33.34, 33.33, 33.33 (spec rule).
        # ⚠️ FOLLOW-UP: "Why not round each share?" -> "Rounding floats can make the
        #    parts not add up to the total. Integer cents + remainder is exact."
        return [base + 1 if i < rem else base for i in range(n)]


class ExactSplitStrategy(SplitStrategy):
    def compute(self, amount_cents, participants, exact_cents=None):
        # WHY: EXACT owns its OWN validation — single responsibility, manager stays thin.
        if exact_cents is None or len(exact_cents) != len(participants):
            raise InvalidExpenseError("exact shares count must match participants")
        if any(s < 0 for s in exact_cents):
            raise InvalidExpenseError("shares must be non-negative")
        if sum(exact_cents) != amount_cents:
            # WHY: the spec's hard rule — shares MUST sum to the total or reject.
            raise InvalidExpenseError(
                f"exact shares {sum(exact_cents)} != total {amount_cents}")
        return list(exact_cents)


class SplitStrategyFactory:
    # ── WHY THIS CLASS ────────────────────────────────────────────────────────
    # The single place that maps the input token (SplitType) -> a strategy object.
    # Strategies are stateless, so we keep one shared instance of each.
    _registry = {
        SplitType.EQUAL: EqualSplitStrategy(),
        SplitType.EXACT: ExactSplitStrategy(),
    }

    @classmethod
    def get(cls, split_type: SplitType) -> SplitStrategy:
        if split_type not in cls._registry:
            raise InvalidExpenseError(f"unsupported split type {split_type}")
        return cls._registry[split_type]

"""The single source of truth for who owes whom."""
from __future__ import annotations

from collections import defaultdict
from contextlib import contextmanager
from typing import Iterator

from models import format_cents


class BalanceSheet:
    # ── WHY THIS CLASS ────────────────────────────────────────────────────────
    # Owns ONE signed number per pair: _bal[a][b] = cents that a owes b. The rule
    # "if a owes b X, then b owes a -X" lives in exactly one method (update).
    # 🎙️ "I gave balances their own object so the antisymmetry rule has one home."
    def __init__(self) -> None:
        self._bal: dict[str, dict[str, int]] = defaultdict(lambda: defaultdict(int))

    @contextmanager
    def _lock(self) -> Iterator[None]:
        # WHY: does NOTHING in the clean version. The thread-safe subclass (§9)
        #      overrides ONLY this to add a real lock. Zero lock code in this file.
        yield

    def update(self, debtor: str, creditor: str, cents: int) -> None:
        # WHY: skip self-debt — covers "payer is also a participant" with no special case.
        if debtor == creditor or cents == 0:
            return
        with self._lock():
            self._bal[debtor][creditor] += cents
            self._bal[creditor][debtor] -= cents      # WHY: keep both sides antisymmetric
            self._cleanup(debtor, creditor)

    def _cleanup(self, a: str, b: str) -> None:
        # WHY: drop a pair the instant it nets to zero so queries never print stale zeros.
        if self._bal[a][b] == 0:
            self._bal[a].pop(b, None)
            self._bal[b].pop(a, None)

    def balances_for(self, user: str) -> list[str]:
        # WHY: one user's view — positive cell means user owes, negative means owed.
        out: list[str] = []
        for other, cents in sorted(self._bal[user].items()):
            if cents > 0:
                out.append(f"{user} owes {other}: {format_cents(cents)}")
            elif cents < 0:
                out.append(f"{other} owes {user}: {format_cents(-cents)}")
        return out

    def all_balances(self) -> list[str]:
        # WHY: print each pair ONCE by only emitting the positive direction.
        out: list[str] = []
        for a in sorted(self._bal):
            for b in sorted(self._bal[a]):
                cents = self._bal[a][b]
                if cents > 0:
                    out.append(f"{a} owes {b}: {format_cents(cents)}")
        return out

"""The orchestrator: validate -> split -> update balances -> record -> notify."""
from __future__ import annotations

import itertools
from collections import defaultdict

from models import (Expense, ExpenseObserver, SplitType, User,
                    UserNotFoundError, InvalidExpenseError, to_cents)
from split_strategies import SplitStrategyFactory
from balance_sheet import BalanceSheet


class ExpenseManager:
    # ── WHY THIS CLASS ────────────────────────────────────────────────────────
    # The brain. Every operation flows through here. It owns the BalanceSheet and
    # never touches raw balance numbers — it goes through the sheet's API.
    def __init__(self, balance_sheet: BalanceSheet | None = None) -> None:
        self._users: dict[str, User] = {}
        self._sheet = balance_sheet or BalanceSheet()
        self._expenses: list[Expense] = []
        self._user_expenses: dict[str, list[Expense]] = defaultdict(list)
        self._observers: list[ExpenseObserver] = []
        self._ids = itertools.count(1)  # WHY: exp-1, exp-2 readable in tests; UUID in prod

    def add_user(self, user: User) -> None:
        self._users[user.user_id] = user

    def register_observer(self, obs: ExpenseObserver) -> None:
        self._observers.append(obs)

    def add_expense(self, paid_by: str, amount, participants: list[str],
                    split_type: SplitType, exact_shares=None) -> Expense:
        # ── validate at the boundary BEFORE mutating anything ──
        if paid_by not in self._users:
            raise UserNotFoundError(f"payer {paid_by} not found")
        if not participants:
            raise InvalidExpenseError("participants cannot be empty")
        for p in participants:
            if p not in self._users:
                raise UserNotFoundError(f"participant {p} not found")
        amount_cents = to_cents(amount)
        if amount_cents <= 0:
            raise InvalidExpenseError("amount must be positive")

        exact_cents = [to_cents(s) for s in exact_shares] if exact_shares is not None else None

        # WHY: Strategy pays off here — manager doesn't know EQUAL vs EXACT math.
        strategy = SplitStrategyFactory.get(split_type)
        shares = strategy.compute(amount_cents, list(participants), exact_cents)

        # ── apply: each participant owes the payer their share ──
        for p, share in zip(participants, shares):
            self._sheet.update(debtor=p, creditor=paid_by, cents=share)

        expense = Expense(f"exp-{next(self._ids)}", paid_by, amount_cents,
                          tuple(participants), split_type, tuple(shares))
        self._expenses.append(expense)
        self._user_expenses[paid_by].append(expense)
        for p in participants:
            if p != paid_by:
                self._user_expenses[p].append(expense)
        for obs in self._observers:
            obs.on_expense_added(expense)
        return expense

    def show_balances(self) -> list[str]:
        res = self._sheet.all_balances()
        return res if res else ["No balances"]

    def show_balances_for(self, user_id: str) -> list[str]:
        if user_id not in self._users:
            raise UserNotFoundError(f"{user_id} not found")
        res = self._sheet.balances_for(user_id)
        return res if res else ["No balances"]

    def expenses_for(self, user_id: str) -> list[Expense]:
        return list(self._user_expenses[user_id])
